-- ==========================================
-- 4. Create Admin Users Table
-- ==========================================
CREATE TABLE admin_users (
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  email TEXT NOT NULL UNIQUE,
  password TEXT NOT NULL
);

-- Seed default admin user
